import { HKIssue } from '@/models/housekeeping';
import { HouseKeepingService } from '@/services/housekeeping.service';
import { Component, Event, EventEmitter, Prop, State, Watch, h } from '@stencil/core';
import moment from 'moment';

@Component({
  tag: 'igl-hk-issues-dialog',
  styleUrl: 'igl-hk-issues-dialog.css',
  scoped: true,
})
export class IglHkIssuesDialog {
  @Prop() open: boolean = false;
  @Prop() unitId: number;
  @Prop() unitName: string;
  @Prop() propertyId: number;
  @Prop() issue: HKIssue;

  @Event() irAfterClose: EventEmitter<void>;

  @State() error: string | null = null;
  @State() isResolving: boolean = false;

  private dialogRef: HTMLIrDialogElement;
  private houseKeepingService = new HouseKeepingService();

  @Watch('open')
  async handleOpenChange(isOpen: boolean) {
    if (isOpen) {
      this.error = null;
      this.dialogRef?.openModal();
    } else {
      this.dialogRef?.closeModal();
    }
  }

  private handleResolve = async () => {
    if (!this.issue || this.isResolving) return;
    this.isResolving = true;
    this.error = null;
    try {
      await this.houseKeepingService.resolveHKIssue({ issue_id: this.issue.id });
      this.dialogRef?.closeModal();
    } catch (e) {
      this.error = e instanceof Error ? e.message : 'Failed to resolve issue. Please try again.';
    } finally {
      this.isResolving = false;
    }
  };

  private renderContent() {
    if (!this.issue || !this.open) return null;

    return (
      <div class="detail-body">
        <div class="meta-row">
          <span class="meta-item">
            <wa-icon name="door-open"></wa-icon>
            <span class="meta-value">{this.issue.unit.name}</span>
          </span>
          <span class="meta-divider"></span>
          <span class="meta-item">
            <wa-icon name="user"></wa-icon>
            <span class="meta-value">{this.issue.housekeeper_name}</span>
          </span>
          <span class="meta-divider"></span>
          <span class="meta-item">
            <wa-icon name="calendar-days"></wa-icon>
            <span class="meta-value">{moment(this.issue.date).format('MMM D, YYYY')}</span>
          </span>
        </div>

        <wa-callout variant="warning" size="small">
          <strong>Reported Issue</strong>
          <p class="description-text">{this.issue.description || 'No description provided.'}</p>
        </wa-callout>

        {this.error && (
          <div class="error-banner" role="alert">
            <wa-icon name="circle-exclamation"></wa-icon>
            {this.error}
          </div>
        )}
      </div>
    );
  }

  render() {
    return (
      <ir-dialog ref={el => (this.dialogRef = el)} label={`Issue #${this.issue?.id}`} onIrDialogAfterHide={() => this.irAfterClose.emit()}>
        {this.renderContent()}

        <div slot="footer" class="dialog-footer">
          <ir-custom-button variant="neutral" size="medium" appearance="filled" onClickHandler={() => this.dialogRef?.closeModal()} disabled={this.isResolving}>
            Close
          </ir-custom-button>
          <ir-custom-button
            variant="brand"
            size="medium"
            appearance="accent"
            onClickHandler={this.handleResolve}
            disabled={this.isResolving || !this.issue}
            loading={this.isResolving}
          >
            Mark as Resolved
          </ir-custom-button>
        </div>
      </ir-dialog>
    );
  }
}
